<template><div class="panel"><div class="section-head"><div><h2>{{ t('dictionaries.title') }}</h2><p>{{ t('dictionaries.description') }}</p></div><el-button type="primary" @click="openType()">{{ t('dictionaries.addType') }}</el-button></div><el-row :gutter="20"><el-col :span="9"><el-table :data="pagedTypes" highlight-current-row @current-change="selectType"><el-table-column prop="code" :label="t('common.code')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button link @click.stop="openType(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click.stop="removeType(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="typeQuery.page" :page-size="typeQuery.size" :total="typeTotal" layout="total, prev, pager, next"/></el-col><el-col :span="15"><div class="section-head"><strong>{{ current?.name || t('dictionaries.selectType') }}</strong><el-button :disabled="!current" @click="openData()">{{ t('dictionaries.addData') }}</el-button></div><template v-if="current"><el-table :data="pagedDataRows"><el-table-column prop="label" :label="t('dictionaries.label')"/><el-table-column prop="dictValue" :label="t('dictionaries.value')"/><el-table-column prop="sortOrder" :label="t('common.sort')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button link @click="openData(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click="removeData(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="dataQuery.page" :page-size="dataQuery.size" :total="dataTotal" layout="total, prev, pager, next"/></template><el-empty v-else :description="t('dictionaries.selectTypeHint')" /></el-col></el-row><el-dialog v-model="typeVisible" :title="t('dictionaries.type')"><el-form label-width="90px"><el-form-item :label="t('common.code')"><el-input v-model="typeForm.code"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="typeForm.name"/></el-form-item><el-form-item :label="t('common.description')"><el-input v-model="typeForm.description"/></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="typeForm.enabled"/></el-form-item></el-form><template #footer><el-button @click="typeVisible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="saveType">{{ t('common.save') }}</el-button></template></el-dialog><el-dialog v-model="dataVisible" :title="t('dictionaries.data')"><el-form label-width="90px"><el-form-item :label="t('dictionaries.label')"><el-input v-model="dataForm.label"/></el-form-item><el-form-item :label="t('dictionaries.value')"><el-input v-model="dataForm.dictValue"/></el-form-item><el-form-item :label="t('common.sort')"><el-input-number v-model="dataForm.sortOrder"/></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="dataForm.enabled"/></el-form-item></el-form><template #footer><el-button @click="dataVisible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="saveData">{{ t('common.save') }}</el-button></template></el-dialog></div></template>
<script setup>import{computed,onMounted,reactive,ref}from'vue';import{ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';const{t}=useI18n();const allTypes=ref([]),allDataRows=ref([]),current=ref(null),typeVisible=ref(false),dataVisible=ref(false),typeForm=reactive({id:null,code:'',name:'',description:'',enabled:true}),dataForm=reactive({id:null,typeCode:'',label:'',dictValue:'',sortOrder:0,enabled:true});const typeQuery=reactive({page:1,size:5}),typeTotal=computed(()=>allTypes.value.length),pagedTypes=computed(()=>allTypes.value.slice((typeQuery.page-1)*typeQuery.size,typeQuery.page*typeQuery.size)),dataQuery=reactive({page:1,size:5}),dataTotal=computed(()=>allDataRows.value.length),pagedDataRows=computed(()=>allDataRows.value.slice((dataQuery.page-1)*dataQuery.size,dataQuery.page*dataQuery.size));async function loadTypes(){allTypes.value=(await http.get('/system/dictionaries/types')).data} /** 选择字典类型并加载右侧数据。 */ async function selectType(row){if(!row)return;current.value=row;dataQuery.page=1;allDataRows.value=(await http.get('/system/dictionaries/data',{params:{typeCode:row.code}})).data} /** 打开类型窗口。 */ function openType(row){Object.assign(typeForm,row?{...row}:{id:null,code:'',name:'',description:'',enabled:true});typeVisible.value=true} /** 保存类型。 */ async function saveType(){typeForm.id?await http.put(`/system/dictionaries/types/${typeForm.id}`,typeForm):await http.post('/system/dictionaries/types',typeForm);typeVisible.value=false;await loadTypes()} /** 删除类型并清理已选类型的右侧状态。 */ async function removeType(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.name}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/system/dictionaries/types/${row.id}`);if(current.value?.id===row.id){current.value=null;allDataRows.value=[];dataQuery.page=1}await loadTypes()} /** 打开字典数据窗口。 */ function openData(row){if(!row&&!current.value)return;Object.assign(dataForm,row?{...row}:{id:null,typeCode:current.value.code,label:'',dictValue:'',sortOrder:0,enabled:true});dataVisible.value=true} /** 保存字典数据。 */ async function saveData(){dataForm.id?await http.put(`/system/dictionaries/data/${dataForm.id}`,dataForm):await http.post('/system/dictionaries/data',dataForm);dataVisible.value=false;await selectType(current.value)} /** 删除字典数据。 */ async function removeData(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.label}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/system/dictionaries/data/${row.id}`);await selectType(current.value)} onMounted(loadTypes)</script>
